INSERT INTO "citation_records" ("id","query_log_id","document_version_id","source_chunk_id","citation_locator","chunk_text_snapshot","created_at","expires_at") VALUES('53c6f000-2480-4f50-926b-e3fc506ff949','a535cce8-5f28-4933-9913-7d06fe7bb503','3d2bd549-707f-4c44-87f1-06c3e703fa46','d91c061d-9a6e-4a02-8db3-9c745ab74b70','lines 1-2',replace('Smoke Test 0418 — AutoRAG 驗收\n這份文件用於驗證 AutoRAG indexing pipeline（task 8.5 / 8.6）是否能把 per-chunk R2 物件正確推到 indexed 狀態。','\n',char(10)),'2026-04-18T17:16:26.392Z','2026-10-15T17:16:26.392Z');
INSERT INTO "citation_records" ("id","query_log_id","document_version_id","source_chunk_id","citation_locator","chunk_text_snapshot","created_at","expires_at") VALUES('18505529-43a0-4639-8684-5cdbc312bb8e','a535cce8-5f28-4933-9913-7d06fe7bb503','3d2bd549-707f-4c44-87f1-06c3e703fa46','e4a1f79f-d858-4ca0-bc87-0ecf0ecc8561','lines 21-22',replace('預期 citation locator\n本文件共三段小節（測試目的、驗收提問腳本、預期 citation locator）。AutoRAG retrieval 應能把使用者的問題 match 到對應段落，並顯示 citationlocator 指向該 chunk。','\n',char(10)),'2026-04-18T17:16:26.392Z','2026-10-15T17:16:26.392Z');
INSERT INTO "citation_records" ("id","query_log_id","document_version_id","source_chunk_id","citation_locator","chunk_text_snapshot","created_at","expires_at") VALUES('a0832970-aea3-47f7-b310-1c405023a5cb','a535cce8-5f28-4933-9913-7d06fe7bb503','3d2bd549-707f-4c44-87f1-06c3e703fa46','21fb3b07-e88e-497a-9c1f-e6e13c41b172','lines 7-11',replace('1. Upload wizard 的 select → upload → finalize → sync 步驟能正常走完\n2. Sync 完成後，R2 bucket 的 normalized-text/<versionId/ 底下會出現 per-chunk 物件\n3. 每個 chunk 物件的 customMetadata 包含 status、versionstate、accesslevel、categoryslug、citationlocator、documentversionid、title\n4. AutoRAG 會自動 crawl 新物件並建立向量索引\n5. documentversions.indexstatus 會從 preprocessing 推進到 smokepending、最後到 indexed','\n',char(10)),'2026-04-18T17:16:26.392Z','2026-10-15T17:16:26.392Z');
