INSERT INTO "messages" ("id","query_log_id","user_profile_id","channel","role","content_redacted","risk_flags_json","redaction_applied","created_at","conversation_id","citations_json","content_text") VALUES('12eafef7-2b92-493c-8020-4f45e152d68f','a535cce8-5f28-4933-9913-7d06fe7bb503','dh9UCNGLmzRlSMXenEFmNvOMknwDx4XA','web','assistant',replace('「AutoRAG 驗收文件的測試目的是什麼？」\n「Smoke Test 0418 預計推進哪些狀態？」\n\nSmoke Test 0418 — AutoRAG 驗收\n這份文件用於驗證 AutoRAG indexing pipeline（task 8.5 / 8.6）是否能把 per-chunk R2 物件正確推到 indexed 狀態。\n\n預期 citation locator\n本文件共三段小節（測試目的、驗收提問腳本、預期 citation locator）。AutoRAG retrieval 應能把使用者的問題 match 到對應段落，並顯示 citationlocator 指向該 chunk。','\n',char(10)),'[]',0,'2026-04-18T17:16:27.179Z','0be94d52-54b1-47bd-b1b4-2bb99fe64085','[{"documentVersionId":"3d2bd549-707f-4c44-87f1-06c3e703fa46"}]',replace('「AutoRAG 驗收文件的測試目的是什麼？」\n「Smoke Test 0418 預計推進哪些狀態？」\n\nSmoke Test 0418 — AutoRAG 驗收\n這份文件用於驗證 AutoRAG indexing pipeline（task 8.5 / 8.6）是否能把 per-chunk R2 物件正確推到 indexed 狀態。\n\n預期 citation locator\n本文件共三段小節（測試目的、驗收提問腳本、預期 citation locator）。AutoRAG retrieval 應能把使用者的問題 match 到對應段落，並顯示 citationlocator 指向該 chunk。','\n',char(10)));
