INSERT INTO "messages" ("id","query_log_id","user_profile_id","channel","role","content_redacted","risk_flags_json","redaction_applied","created_at","conversation_id","citations_json","content_text") VALUES('bf655ead-a1f7-4f1d-89cb-05d3fcd967a7','48deff10-8ba5-4fea-9c70-8c6bc4846003','dh9UCNGLmzRlSMXenEFmNvOMknwDx4XA','web','assistant',replace('採購作業步驟\n1. 需求單位提出採購申請。\n2. 採購人員評估需求並尋找合格供應商。\n3. 取得至少三家報價單進行比價。\n4. 主管簽核後發出採購單。\n5. 驗收入庫與財務付款。\n\n採購流程\n本文件用於人工驗收 5.1 中文檔名保留驗證。','\n',char(10)),'[]',0,'2026-04-19T06:27:47.398Z','8cb08377-e00e-4a36-975d-e486d3777cae','[{"documentVersionId":"793f61e7-a086-4829-9832-01b5db7381bd"},{"documentVersionId":"92f763cf-c41e-4f61-993f-64930ea920a3"}]',replace('採購作業步驟\n1. 需求單位提出採購申請。\n2. 採購人員評估需求並尋找合格供應商。\n3. 取得至少三家報價單進行比價。\n4. 主管簽核後發出採購單。\n5. 驗收入庫與財務付款。\n\n採購流程\n本文件用於人工驗收 5.1 中文檔名保留驗證。','\n',char(10)));
